Here's the Python code to solve this problem:
```python
def is_palindrome(num_str, base=10):
    return num_str == num_str[::-1]

def to_base(n, base):
    if n == 0:
        return "0"
    digits = []
    while n:
        digits.append(int(n % base))
        n //= base
    return ''.join(str(x) for x in digits[::-1])

# Find the smallest 5-digit palindrome in base 2
for i in range(1, 32):
    base_2_palindrome = f"{i:05b}"
    if is_palindrome(base_2_palindrome):
        for base in range(2, 37):
            new_number = int(base_2_palindrome, base)
            if 1 <= new_number < 1000 and is_palindrome(to_base(new_number, base)):
                smallest_palindrome = base_2_palindrome
                break
        else:
            continue
        break

print(smallest_palindrome)
